val focalMean: RasterRDD[Double] = RasterOperationsFocal.slidingWindow(rasterRDD, 1, (values: Array[Float], defined: Array[Boolean]) => {
  var sum = 0.0
  var count = 0
  var i = 0
  while (i < values.length) {
    if (defined(i)) {
      sum += values(i).toDouble
      count += 1
    }
    i += 1
  }
  if (count == 0) Double.NaN else sum / count
})

val sample = focalMean.take(1)
require(sample.nonEmpty, "empty result for slidingWindow")
val witness = sample(0)._2
require(!java.lang.Double.isNaN(witness) && !java.lang.Double.isInfinite(witness), s"non-finite witness: $witness")
println("__CHECK__ slidingWindow " + witness)

