  if (tile.isDefined(x, y)) {
    val v = tile.getPixelValue(x, y)
    require(!java.lang.Float.isNaN(v) && !java.lang.Float.isInfinite(v), s"invalid pixel value at ($x,$y)")
    pixelCount += 1
  }
}
